export const 借潮玉符 = (bi) => {
    const u = bi.u, k = 2.3;
    const X = (c) => (c - 5.05) * k;
    const Z = (r) => (r - 0.7) * k + 0.9;
    const 抖 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 摺 = (x0, x1, rT, rB, n, 左起 = true, 寬 = 0.4) => 抖(pa => {
        const p = n > 1 ? (rB - rT) / (n - 1) : 0;
        let dir = 左起 ? 1 : -1, y = rT;
        pa.M(X(dir > 0 ? x0 : x1), Z(y));
        for (let i = 0; i < n; i++) {
            const xe = dir > 0 ? x1 : x0;
            if (i < n - 1) {
                pa.L(X(xe - dir * p * 0.35), Z(y));
                pa.C(X(xe + dir * p * 1.05), Z(y - p * 0.05), X(xe + dir * p * 1.05), Z(y + p * 1.05), X(xe - dir * p * 0.35), Z(y + p));
                y += p;
                dir = -dir;
            }
            else
                pa.L(X(xe), Z(y));
        }
    }, 寬);
    // 頭三疊帶（左厂臂）
    摺(0.6, 3.6, 0.95, 6.2, 9);
    抖(p => p.M(X(0.52), Z(2.3)).C(X(0.28), Z(3.3), X(0.28), Z(5.2), X(0.52), Z(6.3)), 0.4);
    摺(3.9, 6.6, 0.85, 5.35, 8);
    摺(7.0, 9.7, 0.75, 5.9, 9);
    // 滿幅五摺
    摺(0.8, 9.7, 6.35, 9.3, 5);
    // 山垂帶：厂臂＋梳桁懸齒五環＋右三摺
    抖(p => p.M(X(0.5), Z(9.45)).C(X(0.28), Z(10.1), X(0.3), Z(11.0), X(0.5), Z(11.6)), 0.4);
    抖(pa => {
        pa.M(X(0.85), Z(9.6));
        let x = 0.85;
        for (const cx of [1.35, 2.45, 3.55, 4.65, 5.75]) {
            pa.L(X(cx - 0.3), Z(9.6));
            pa.C(X(cx - 0.42), Z(10.5), X(cx - 0.3), Z(11.15), X(cx), Z(11.15));
            pa.C(X(cx + 0.3), Z(11.15), X(cx + 0.42), Z(10.5), X(cx + 0.3), Z(9.62));
            x = cx + 0.3;
        }
        pa.L(X(7.1), Z(9.58));
    }, 0.4);
    摺(6.0, 9.6, 9.75, 11.4, 3, false);
    // 滿幅五摺
    摺(0.7, 9.7, 11.65, 14.35, 5);
    // 對疊帶三具
    摺(0.6, 3.6, 14.55, 16.4, 4);
    摺(3.9, 6.4, 14.5, 16.3, 4);
    摺(6.6, 9.6, 14.5, 16.3, 4);
    // 亖框帶（隅飄雙臂・內桁二中杙・底桁）
    線(p => p.M(X(1.1), Z(16.7)).L(X(9.4), Z(16.62)), 0.42);
    抖(p => p.M(X(1.15), Z(16.72)).L(X(0.7), Z(16.42)), 0.34);
    抖(p => p.M(X(9.35), Z(16.65)).L(X(9.8), Z(16.35)), 0.34);
    抖(p => p.M(X(0.9), Z(16.85)).C(X(0.7), Z(17.5), X(0.7), Z(18.4), X(0.95), Z(19.0)), 0.4);
    抖(p => p.M(X(9.5), Z(16.8)).C(X(9.7), Z(17.4), X(9.7), Z(18.3), X(9.5), Z(18.95)), 0.4);
    線(p => p.M(X(1.2), Z(17.3)).L(X(9.3), Z(17.24)), 0.36);
    線(p => p.M(X(1.2), Z(17.95)).L(X(9.3), Z(17.89)), 0.36);
    線(p => p.M(X(4.9), Z(17.35)).L(X(4.88), Z(18.0)), 0.38);
    線(p => p.M(X(1.15), Z(18.55)).L(X(9.35), Z(18.48)), 0.4);
    // 底二摺承波曲行（弓 S 三連右曳）
    摺(0.9, 9.5, 19.55, 20.2, 2);
    for (const x0 of [1.5, 3.9, 6.3])
        抖(p => p.M(X(x0 + 1.6), Z(20.55))
            .C(X(x0), Z(20.45), X(x0 - 0.2), Z(21.0), X(x0 + 0.7), Z(21.1))
            .C(X(x0 + 1.5), Z(21.2), X(x0 + 1.4), Z(21.8), X(x0 + 0.5), Z(21.9)), 0.4);
    抖(p => p.M(X(8.2), Z(20.5)).C(X(9.3), Z(20.6), X(9.5), Z(21.4), X(9.0), Z(22.0)), 0.4);
    // 底欄：豎分三欄（桁三・弓弓高低對・桁三尾曳）
    線(p => p.M(X(2.85), Z(22.9)).L(X(2.83), Z(26.0)), 0.4);
    線(p => p.M(X(7.45), Z(22.85)).L(X(7.43), Z(25.95)), 0.4);
    for (const z of [23.3, 24.1, 24.9])
        線(p => p.M(X(0.6), Z(z)).L(X(2.4), Z(z - 0.03)), 0.36);
    抖(p => p.M(X(4.85), Z(23.1))
        .C(X(3.4), Z(23.0), X(3.2), Z(23.8), X(4.1), Z(24.0))
        .C(X(4.9), Z(24.2), X(4.9), Z(24.9), X(4.0), Z(25.0))
        .C(X(3.3), Z(25.1), X(3.4), Z(25.9), X(4.2), Z(26.0)), 0.4);
    抖(p => p.M(X(7.1), Z(23.05))
        .C(X(5.7), Z(23.0), X(5.55), Z(23.7), X(6.4), Z(23.9))
        .C(X(7.2), Z(24.1), X(7.2), Z(24.8), X(6.3), Z(24.9))
        .C(X(5.6), Z(25.05), X(5.7), Z(25.8), X(6.5), Z(25.9)), 0.4);
    for (const z of [23.3, 24.1, 24.9])
        線(p => p.M(X(7.9), Z(z)).L(X(9.5), Z(z - 0.03)), 0.36);
    抖(p => p.M(X(9.4), Z(25.3)).C(X(9.6), Z(25.8), X(9.5), Z(26.2), X(9.2), Z(26.35)), 0.38);
};
